import sys

def time_to_minutes(t):
    h, m = t.split(':')
    return int(h) * 60 + int(m)

total = 0
for line in sys.argv[1].strip().split('\n'):
    line = line.strip()
    if line:
        start, end = line.split('-')
        total += time_to_minutes(end) - time_to_minutes(start)

sys.stdout.write(str(total) + '\n')

import sys
from collections import defaultdict

data = sys.argv[1]
counts = defaultdict(int)

for line in data.splitlines():
    if ': ' in line:
        level, message = line.split(': ', 1)
        if level.strip() == 'ERROR':
            first_word = message.split()[0] if message.split() else ''
            if first_word:
                counts[first_word] += 1

for word, count in sorted(counts.items(), key=lambda x: -x[1]):
    sys.stdout.write(f"{word} {count}\n")

